	}

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		// Capture stderr if available
		stderr := ""
		if exitErr, ok := err.(*exec.ExitError); ok {
			stderr = string(exitErr.Stderr)
		}
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, stderr)
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		// Capture stderr if available
		stderr := ""
		if exitErr, ok := err.(*exec.ExitError); ok {
			stderr = string(exitErr.Stderr)
		}
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, stderr)
	}

	// Read the output file to return as string
	outputBytes, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(outputBytes), nil
}

