package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to query SLB information,
// formats the output with jq, and writes the result to the specified output file.
// It returns the command output and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Step 1: Execute aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	var aliyunOut bytes.Buffer
	var aliyunErr bytes.Buffer
	aliyunCmd.Stdout = &aliyunOut
	aliyunCmd.Stderr = &aliyunErr

	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %v, stderr: %s", err, aliyunErr.String())
	}

	// Step 2: Pipe aliyun output to jq for formatting
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = strings.NewReader(aliyunOut.String())
	var jqOut bytes.Buffer
	var jqErr bytes.Buffer
	jqCmd.Stdout = &jqOut
	jqCmd.Stderr = &jqErr

	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("jq command failed: %v, stderr: %s", err, jqErr.String())
	}

	// Step 3: Write formatted output to file
	formattedOutput := jqOut.String()
	if err := os.WriteFile(outputFile, []byte(formattedOutput), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %v", err)
	}

	return formattedOutput, nil
}

func main() {
	// Example usage with command-line arguments
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <loadBalancerName> <outputFile>")
		fmt.Println("Example: go run main.go my-slb output.json")
		return
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	output, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully exported SLB data to %s\n", outputFile)
	fmt.Printf("Output preview (first 500 chars):\n%.500s\n", output)
}

