	if !strings.HasSuffix(outputFile, ".json") {
		return "", fmt.Errorf("outputFile must have .json extension")
	}

	// Create the commands without using shell pipeline
	// First command: aliyun slb DescribeLoadBalancers
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

