package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to query SLB information,
// formats the output with jq, and writes the result to the specified output file.
// It returns the command output as a string and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Build the aliyun command arguments
	aliyunArgs := []string{"slb", "DescribeLoadBalancers"}
	if loadBalancerName != "" {
		aliyunArgs = append(aliyunArgs, "--LoadBalancerName", loadBalancerName)
	}

	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", aliyunArgs...)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun's stdout to jq's stdin
	pipeReader, pipeWriter := io.Pipe()
	aliyunCmd.Stdout = pipeWriter
	jqCmd.Stdin = pipeReader

	// Create buffers to capture output
	var jqOutput bytes.Buffer
	var errorOutput bytes.Buffer
	jqCmd.Stdout = &jqOutput
	aliyunCmd.Stderr = &errorOutput
	jqCmd.Stderr = &errorOutput

	// Start the jq command first
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		pipeWriter.Close()
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, errorOutput.String())
	}

	// Close the write end of the pipe to signal EOF to jq
	pipeWriter.Close()

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, errorOutput.String())
	}

	// Get the final output
	finalOutput := jqOutput.String()

	// Write output to file if specified
	if outputFile != "" {
		file, err := os.Create(outputFile)
		if err != nil {
			return finalOutput, fmt.Errorf("failed to create output file: %w", err)
		}
		defer file.Close()

		if _, err := file.WriteString(finalOutput); err != nil {
			return finalOutput, fmt.Errorf("failed to write to output file: %w", err)
		}
	}

	return finalOutput, nil
}

func main() {
	// Example usage
	output, err := QuerySLBAndExport("my-loadbalancer", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Success! Output length: %d characters\n", len(output))
}

