import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Validate output file path is safe
	if !filepath.IsLocal(outputFile) {
		return "", fmt.Errorf("outputFile path must be local")
	}

	// Create the first command: aliyun CLI
	cmd1 := exec.Command(
		"aliyun",
		"slb",
		"DescribeLoadBalancers",
		"--LoadBalancerName",
		loadBalancerName,
	)

	// Create the second command: jq
	cmd2 := exec.Command(
		"jq",
		".LoadBalancers.LoadBalancer[]",
	)

	// Pipe cmd1's stdout to cmd2's stdin
	pipe, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	cmd2.Stdin = pipe

	// Start the first command
	if err := cmd1.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Run the second command and capture output
	outputBytes, err := cmd2.Output()
	if err != nil {
