		if exitErr, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, exitErr.Stderr)
		}
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Wait for the first command to complete
	if err := cmd1.Wait(); err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, exitErr.Stderr)
		}
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Write output to file
	if err := os.WriteFile(outputFile, outputBytes, 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return string(outputBytes), nil
}

