    // Write the captured output to the specified file
    if err := os.WriteFile(outputFile, out.Bytes(), 0644); err != nil {
        return "", fmt.Errorf("failed to write to output file: %v", err)
    }

    return outputString, nil
}

func main() {
    // Expect two command-line arguments: loadBalancerName and outputFile
    if len(os.Args) != 3 {
        fmt.Println("Usage: program <loadBalancerName> <outputFile>")
