		return "", fmt.Errorf("outputFile contains invalid characters")
	}

	// Create the output file first to ensure we have write permissions
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Build the aliyun command without shell
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Build the jq command without shell
