package main

import (
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters to prevent path traversal and injection
	if strings.ContainsAny(loadBalancerName, "\"'`$|><&;\n\r\t") {
		return "", fmt.Errorf("invalid characters in loadBalancerName parameter")
	}
	if strings.ContainsAny(outputFile, "\"'`$|><&;\n\r\t") {
		return "", fmt.Errorf("invalid characters in outputFile parameter")
	}

	// Additional validation for outputFile path
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the output file first to ensure we have write permissions
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	file.Close()

	// Build the aliyun command without shell interpolation
	aliyunCmd := exec.Command(
		"aliyun",
		"slb",
		"DescribeLoadBalancers",
		"--LoadBalancerName",
		loadBalancerName,
	)

	// Build the jq command without shell interpolation
	jqCmd := exec.Command(
		"jq",
		".LoadBalancers.LoadBalancer[]",
	)

	// Create a pipe to connect aliyun's stdout to jq's stdin
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	jqCmd.Stdin = pipe

	// Create output file for jq's stdout
	output, err := os.OpenFile(outputFile, os.O_WRONLY|os.O_TRUNC, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to open output file: %w", err)
	}
	defer output.Close()
	jqCmd.Stdout = output

	// Start the jq command first (it will wait for input)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Capture stderr from both commands
	var stderrBytes []byte
	aliyunStderr, err := aliyunCmd.StderrPipe()
	if err == nil {
		aliyunErrBytes, _ := io.ReadAll(aliyunStderr)
		stderrBytes = append(stderrBytes, aliyunErrBytes...)
	}

	jqStderr, err := jqCmd.StderrPipe()
	if err == nil {
		jqErrBytes, _ := io.ReadAll(jqStderr)
		stderrBytes = append(stderrBytes, jqErrBytes...)
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		return string(stderrBytes), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return string(stderrBytes), fmt.Errorf("jq command failed: %w", err)
	}

	// Read the output file content to return
	content, err := os.ReadFile(outputFile)
	if err != nil {
		return string(stderrBytes), fmt.Errorf("failed to read output file: %w", err)
	}

	return string(content), nil
}

