package main

import (
    "bytes"
    "fmt"
    "io"
    "os"
    "os/exec"
)

func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
    // First command: aliyun CLI to query SLB
    cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

    // Second command: jq to format JSON output
    cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

    // Pipe stdout of cmd1 to stdin of cmd2
    stdout1, err := cmd1.StdoutPipe()
    if err != nil {
        return "", err
    }
    cmd2.Stdin = stdout1

    // Create output file
    file, err := os.Create(outputFile)
    if err != nil {
        return "", err
    }
    defer file.Close()

    // Buffer to capture output and multi-writer to write to both buffer and file
    var outputBuffer bytes.Buffer
    multiWriter := io.MultiWriter(&outputBuffer, file)
    cmd2.Stdout = multiWriter
    cmd2.Stderr = os.Stderr // Send stderr to console for debugging

    // Start cmd2 first as it receives input from cmd1
    if err := cmd2.Start(); err != nil {
        return "", err
    }

    // Start cmd1
    if err := cmd1.Start(); err != nil {
        cmd2.Process.Kill() // Clean up if cmd1 fails
        return "", err
    }

    // Wait for cmd1 to finish
    if err := cmd1.Wait(); err != nil {
        cmd2.Process.Kill()
        return "", err
    }

    // Wait for cmd2 to finish
    if err := cmd2.Wait(); err != nil {
        return "", err
    }

    // Return captured output as string
    return outputBuffer.String(), nil
}

func main() {
    // Simple command-line interface for testing
    if len(os.Args) != 3 {
        fmt.Println("Usage: go run main.go <loadBalancerName> <outputFile>")
        os.Exit(1)
    }

    loadBalancerName := os.Args[1]
    outputFile := os.Args[2]

    output, err := QuerySLBAndExport(loadBalancerName, outputFile)
    if err != nil {
        fmt.Printf("Error: %v\n", err)
        os.Exit(1)
    }

    fmt.Printf("Query successful. Output written to %s and captured: %s\n", outputFile, output)
}

